import click

@click.command()
@click.option('--name', default='World', help='Who to greet')
def greet(name):
    click.echo(f'Hello, {name}!')

if __name__ == '__main__':
    greet()

@cli.command()
@click.argument('filename')
def build(filename):
    click.echo(f'Building {filename}')

@cli.command()
def deploy():
    click.echo('Deploying...')

@click.group()
@click.option('--env', default='prod')
@click.pass_context
def cli(ctx, env):
    ctx.ensure_object(dict)
    ctx.obj['env'] = env

@cli.command()
@click.pass_context
def status(ctx):
    env = ctx.obj['env']
    click.echo(f'Checking {env} status...')
